parameters.jsCode:
const products = $('Airtable - List Products').all().map(i => i.json);
const locations = $('Airtable - List Locations').all().map(i => i.json);
const req = $('Webhook - List Products').first().json;

function asArray(v) {
  if (v == null) return [];
  return Array.isArray(v) ? v : [v];
}

function stripIndexPrefix(x) {
  if (x == null) return null;
  const s = String(x);
  const m = s.match(/^\d+:(rec[a-zA-Z0-9]+)/);
  return m ? m[1] : s;
}

function parseAllowedLocations(req) {
  const q = req?.query || {};

  // New version: storage_locations_json=["Loc A","Loc B"]
  if (q.storage_locations_json) {
    try {
      const parsed = JSON.parse(q.storage_locations_json);
      return asArray(parsed).map(x => String(x).trim()).filter(Boolean);
    } catch (e) {
      // Fall through to legacy handling
    }
  }

  // Optional comma-separated version: storage_locations=Loc A,Loc B
  if (q.storage_locations) {
    return String(q.storage_locations)
      .split(",")
      .map(x => x.trim())
      .filter(Boolean);
  }

  // Legacy version: storage_location=Loc A
  if (q.storage_location) {
    return [String(q.storage_location).trim()].filter(Boolean);
  }

  // Empty means no location filter, preserving reviewer/broad legacy behavior.
  return [];
}

const allowedLocations = parseAllowedLocations(req);
const allowedLocationSet = new Set(allowedLocations.map(x => x.toLowerCase()));

const locById = new Map();
for (const rec of locations) {
  const f = rec.fields ?? rec;
  const name = (f.name ?? "").toString().trim();
  if (rec.id && name) locById.set(rec.id, name);
}

const EXCLUDE_LOCATIONS = new Set(["Shipped", "Consumed", "Expired"]);

const out = [];

for (const rec of products) {
  const f = rec.fields ?? rec;
  const product_id = f.product_id;
  if (!product_id) continue;

  const locIds = asArray(f.storage_location)
    .map(stripIndexPrefix)
    .filter(x => x && x !== "undefined");

  const locNames = locIds
    .map(id => locById.get(id))
    .filter(Boolean);

  if (locNames.some(n => EXCLUDE_LOCATIONS.has(n))) continue;

  const primaryLocation = locNames[0] ?? null;

  // If allowed locations were supplied, product must be in at least one of them.
  if (
    allowedLocationSet.size > 0 &&
    !locNames.some(n => allowedLocationSet.has(String(n).trim().toLowerCase()))
  ) {
    continue;
  }

  out.push({
    airtable_record_id: rec.id,
    mushroomprocess_product_id: product_id,
    item_name: asArray(f.name)[0] ?? null,
    strain: asArray(f.species_strain)[0] ?? null,
    net_weight_g: f.net_weight_g ?? null,
    unit: "g",
    storage_location: primaryLocation,
    storage_locations: locNames,
  });
}

return [{
  json: {
    ok: true,
    data: out,
    filter: {
      storage_locations: allowedLocations
    }
  }
}];
